esting();    CompilerInput input = new CompilerInput(        JSSourceFile.fromCode(" [testcode] ", js));    if (inputsById == null) {      inputsById = Maps.newHashMap();    }    inputsById.put(input.getInputId(), input);    return input.getAstRoot(this);  }  @Override  ErrorReporter getDefaultErrorReporter() {    return defaultErrorReporter;  }  //------------------------------------------------------------------------  // Convert back to source code  //------------------------------------------------------------------------  /**   * Converts the main parse tree back to js code.   */  public String toSource() {    return runInCompilerThread(new Callable<String>() {      @Override      public String call() throws Exception {        Tracer tracer = newTracer("toSource");        try {          CodeBuilder cb = new CodeBuilder();          if (jsRoot != null) {            int i = 0;            for (Node scriptNode = jsRoot.getFirstChild();                 scriptNode != null;                 scriptNode = scriptNode.getNext()) {              toSource(cb, i++, scriptNode);            }          }          return cb.toString();        } finally {          stopTracer(tracer, "toSource");        }      }    });  }  /**   * Converts the parse tree for each input back to js code.   */  public String[] toSourceArray() {    return runInCompilerThread(new Callable<String[]>() {      @Override      public String[] call() throws Exception {        Tracer tracer = newTracer("toSourceArray");        try {          int numInputs = inputs.size();          String[] sources = new String[numInputs];          CodeBuilder cb = new CodeBuilder();          for (int i = 0; i < numInputs; i++) {            Node scriptNode = inputs.get(i).getAstRoot(Compiler.this);            cb.reset();            toSource(cb, i, scriptNode);            sources[i] = cb.toString();          }          return sources;        } finally {          stopTracer(tracer, "toSourceArray");        }      }    });  }  /**  