 = "{SyntheticVarsDeclar}";  private CompilerInput synthesizedExternsInput = null;  @Override  void addChangeHandler(CodeChangeHandler handler) {    codeChangeHandlers.add(handler);  }  @Override  void removeChangeHandler(CodeChangeHandler handler) {    codeChangeHandlers.remove(handler);  }  /**   * All passes should call reportCodeChange() when they alter   * the JS tree structure. This is verified by CompilerTestCase.   * This allows us to optimize to a fixed point.   */  @Override  public void reportCodeChange() {    for (CodeChangeHandler handler : codeChangeHandlers) {      handler.reportChange();    }  }  @Override  public CodingConvention getCodingConvention() {    CodingConvention convention = options.getCodingConvention();    convention = convention != null ? convention : defaultCodingConvention;    return convention;  }  @Override  public boolean isIdeMode() {    return options.ideMode;  }  @Override  public boolean acceptEcmaScript5() {    switch (options.getLanguageIn()) {      case ECMASCRIPT5:      case ECMASCRIPT5_STRICT:        return true;    }    return false;  }  public LanguageMode languageMode() {    return options.getLanguageIn();  }  @Override  public boolean acceptConstKeyword() {    return options.acceptConstKeyword;  }  @Override  Config getParserConfig() {    if (parserConfig == null) {      Config.LanguageMode mode;      switch (options.getLanguageIn()) {        case ECMASCRIPT3:          mode = Config.LanguageMode.ECMASCRIPT3;          break;        case ECMASCRIPT5:          mode = Config.LanguageMode.ECMASCRIPT5;          break;        case ECMASCRIPT5_STRICT:          mode = Config.LanguageMode.ECMASCRIPT5_STRICT;          break;        default:          throw new IllegalStateException("unexpected language mode");      }      parserConfig = ParserRunner.createConfig(        isIdeMode(),        mode,        acceptConstKeyword(),        options.extraAnnotationNames);    }    return parserConfig;  }  @Override  public boolean isTypeChec